using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ── CalculateTotal: DataRow for simple inline cases ──

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData with ValueTuples for edge/error cases ──

    [TestMethod]
    [DynamicData(nameof(InvalidQuantityData))]
    public void CalculateTotal_NegativeQuantity_Throws(
        decimal unitPrice, int quantity, decimal taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidQuantityData =>
    [
        (10m, -1, 0.1m),
        (5m, -100, 0.0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidUnitPriceData))]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        decimal unitPrice, int quantity, decimal taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidUnitPriceData =>
    [
        (-1m, 1, 0.1m),
        (-0.01m, 10, 0.0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidTaxRateData))]
    public void CalculateTotal_InvalidTaxRate_Throws(
        decimal unitPrice, int quantity, decimal taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidTaxRateData =>
    [
        (10m, 1, -0.01m),
        (10m, 1, 1.01m),
        (10m, 1, 2.0m),
    ];

    // ── ApplyDiscount: DataRow for common scenarios ──

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(59.99, 25.0, 44.9925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, any discount")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.0)]
    [DataRow(100.01)]
    [DataRow(200.0)]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ── FormatPrice: DynamicData with TestDataRow for display names ──

    [TestMethod]
    [DynamicData(nameof(FormatPriceData))]
    public void FormatPrice_FormatsCorrectly(
        decimal price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice(price, currencySymbol);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<TestDataRow<(decimal price, string symbol, string expected)>> FormatPriceData =>
    [
        new((9.99m, "$", "$9.99")) { DisplayName = "USD" },
        new((1234.50m, "€", "€1234.50")) { DisplayName = "Euro" },
        new((0m, "£", "£0.00")) { DisplayName = "Zero GBP" },
        new((7.1m, "¥", "¥7.10")) { DisplayName = "Yen, pad decimals" },
    ];

    [TestMethod]
    public void FormatPrice_DefaultCurrency_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.StartsWith("$", result);
        Assert.AreEqual("$42.00", result);
    }
}

